var e=[{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`침식체들이 기지 안쪽으로 들어오지 못하게 막아!`,JPN:`侵食体を基地の中に入らせるな！`,ENG:`Block the C.O.s from entering the base!`,TWN:`必須阻止侵蝕體進入基地內部！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`소령님이 돌아오실 때까지 버텨야 한다!`,JPN:`少佐がお戻りになるまで持ちこたえるんだ！`,ENG:`We hold here until Major comes back!`,TWN:`少校回來之前，務必堅持住！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`뭔가 이상해! 소령님이 기지를 비우자마자 이렇게 보란듯이 몰려들다니!`,JPN:`何かが変だ！　少佐が基地を空けて間もない、このタイミングで押し寄せてくるなんてよ！`,ENG:`Something's wrong! C.O.s started flooding in just as Major left the base!`,TWN:`太奇怪了！少校剛剛離開基地，侵蝕體就這樣來勢洶洶！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_B`,text:{KOREA:`젠장, 소령님이 없어도 여길 지킬 수 있다는 걸 보여주는 거야!`,JPN:`くそ、少佐がいらっしゃらなくてもここを守れることを示すんだ！`,ENG:`Dammit! Let's show them that we can fend them off even without Major!`,TWN:`可惡，我要讓他們知道即使少校不在，我們也能堅守住這裡！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},C:null,R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_B`,text:{KOREA:`기갑 병력을 앞으로! 방위선을 사수한다!`,JPN:`機甲兵力を前方へ！　防衛線を死守するぞ！`,ENG:`Armored troops to the front! Protect the line!`,TWN:`裝甲部隊衝上去！死守防線！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},C:null,R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_B`,text:{KOREA:`포격 개시!`,JPN:`砲撃開始！`,ENG:`Fire!`,TWN:`開火！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},C:null,R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}},{id:`L24_1`,type:`dialog`,speaker:null,text:{KOREA:`지금이다! 모두 일제 사격!`,JPN:`今だ！　全員一斉射撃！`,ENG:`NOW! All units, volley fire!`,TWN:`就是現在！開火！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},C:null,R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}},{id:`L25_1`,type:`dialog`,speaker:null,text:{KOREA:`포격으로 갑피가 벗겨진 녀석부터 집중 사격한다!`,JPN:`砲撃で甲皮が剥がれた奴を集中的に狙え！`,ENG:`Focus fire on the ones who have their armor blasted off from the bombardment!`,TWN:`集中射擊外殼脫落的傢伙！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},C:null,R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}},{id:`L31_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`좋아, 이 기세라면 함선이 돌아올 때까지 침식체들을 막아낼 수 있겠어!`,JPN:`よし、この勢いなら艦船が戻るまで侵食体を止められそうだ！`,ENG:`Good! I think we can fend them off until the ship returns!`,TWN:`幹得好，照這個氣勢，艦船返回之前，應該可以擋住侵蝕體了！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:null,C:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}},{id:`L32_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`잠깐, 저건!?`,JPN:`ちょっと待て、あれは！？`,ENG:`Wait, what's that?!`,TWN:`等等，那是？`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:null,C:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}},{id:`L37_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`모두 긴장해! 3종이 나타났다!`,JPN:`全員気を引き締めろ！　第3種が現れたぞ！`,ENG:`Stay frosty, men! A category 3 just appeared!`,TWN:`全員注意！出現3類侵蝕體！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:null,C:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}},{id:`L38_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`일반적인 화력은 먹히지 않는다! 쓰러트리는 게 아니라 버티는 걸 목표로……!`,JPN:`普通の火力じゃ通用しない！　倒すのでなく持ちこたえることを目標とし……！`,ENG:`Normal firepower won't work! Changing objectives from elimination to holding the line...!`,TWN:`普通火力無法發揮作用！目標不是擊殺，堅持住就好……！`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:null,C:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}},{id:`L42_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`어? 하나가…… 아니야?`,JPN:`なに？　一匹じゃ……ない？`,ENG:`Huh? It's not... just one?`,TWN:`不，不止一隻嗎？`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:null,C:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}},{id:`L43_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`하나…… 둘…… 셋……?`,JPN:`いち……に……さん……？`,ENG:`One... Two... Three...?`,TWN:`一……二……三，三隻？`},stage:{bg:`COUNTERSIDE_BASE`,slots:{L:null,C:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`},R:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`}}}}];export{e as default};